SELECT ?answer WHERE {
  wd:Q761383 wdt:P138 ?answer.
}

SELECT DISTINCT ?answer WHERE {
  wd:Q14665 wdt:P710 ?answer.
  ?answer wdt:P31 wd:Q16521. # Ensures the participant is an animal
}

SELECT ?answer WHERE {
  ?answer wdt:P451 wd:Q4463198;  # Unmarried partner: Triss Merigold
          wdt:P451 wd:Q4205826.  # Unmarried partner: Yennefer of Vengerberg
}

SELECT ?answer WHERE {
  VALUES ?founder { wd:Q1739008 wd:Q15934341 wd:Q18653685 wd:Q18659347 wd:Q20689208 }
  ?founder ?property wd:Q19211.
  ?founder rdfs:label ?answer.
  FILTER(LANG(?answer) = "en")
}

