SELECT (COUNT(?person) AS ?answer) WHERE {
  ?person p:P39 ?statement.
  ?statement ps:P39 wd:Q1048744;
             pq:P580 ?start;
             pq:P582 ?end.
  FILTER(?end < "1964-10-14T00:00:00Z") # Leonid Brezhnev's start date
}

SELECT (COUNT(DISTINCT ?person) AS ?answer) WHERE {  
  ?person p:P39 ?statement.  
  ?statement ps:P39 wd:Q218295;  
             pq:P580 ?start.  
  FILTER(YEAR(?start) > 1990).  
}

